import psycopg2

def connect_db():
    try:
        conn = psycopg2.connect(
            host="localhost",
            database="your_database",
            user="your_username",
            password="your_password"
        )
        return conn
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)

def search_users(**kwargs):
    conn = connect_db()
    cur = conn.cursor()

    query = """
        SELECT *
        FROM users
        WHERE {}
    """.format(
        " AND ".join([
            "{} = %s".format(key)
            for key in kwargs.keys()
        ])
    )

    params = list(kwargs.values())

    try:
        cur.execute(query, params)
        rows = cur.fetchall()
        return rows
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)

    finally:
        if conn:
            cur.close()
            conn.close()

# Example usage:
print(search_users(username='john', role='admin', status='active'))